/**
 * 归档下载模块
 *
 * 提供基于任务的异步 ZIP 下载机制：
 * 1. 调用方通过 startDownloadJob() 启动任务
 * 2. 调用方通过 getJobProgress() 轮询进度
 * 3. 任务 ready 后，可通过票据端点下载归档（底层数据由 getJobBuffer() 读取）
 *
 * 架构说明：
 * - 任务保存在内存 Map 中，按 TTL 定时清理
 * - Graph API 使用请求携带的用户令牌，经 OBO 流程换取 Graph Token
 * - 文件夹会递归展开，并处理 @odata.nextLink 分页
 * - 文件写入 archiver ZIP 流，归档完成后缓存在内存中
 * - 每个任务最多 500 个文件或 500 MB
 *
 * 使用到的 Graph 端点：
 *   GET /drives/{driveId}/items/{itemId}          - 查询项目元数据
 *   GET /drives/{driveId}/items/{itemId}/children - 列出文件夹子项
 *   GET /drives/{driveId}/items/{itemId}/content  - 下载文件内容流
 */

import archiver from "archiver";
import { PassThrough } from "stream";
import { createGraphClient, getGraphToken } from "./auth";
import { v4 as uuidv4 } from "uuid";

// ─────────────────────────  常量区  ──────────────────────────────────────

const MAX_FILES = 500;
const MAX_BYTES = 500 * 1024 * 1024; // 500 MB
const JOB_TTL_MS = 10 * 60 * 1000; // 10 分钟
const DOWNLOAD_TICKET_TTL_MS = 60 * 1000; // 1 分钟

// ─────────────────────────  类型定义  ───────────────────────────────────────

export type JobStatus = "queued" | "preparing" | "zipping" | "ready" | "failed";

export interface JobProgress {
  status: JobStatus;
  processedFiles: number;
  totalFiles: number;
  currentItem: string;
  errors: string[];
}

interface Job extends JobProgress {
  zipBuffer?: Buffer;
  createdAt: number;
}

interface DownloadTicketRecord {
  jobId: string;
  filename: string;
  expiresAt: number;
}

// ─────────────────────────  任务与票据存储  ─────────────────────────────────

const jobs = new Map<string, Job>();
const downloadTickets = new Map<string, DownloadTicketRecord>();

// 定时清理过期任务与过期票据（每 2 分钟执行一次）
setInterval(
  () => {
    const now = Date.now();
    for (const [id, job] of jobs) {
      if (now - job.createdAt > JOB_TTL_MS) {
        jobs.delete(id);
      }
    }

    for (const [ticket, record] of downloadTickets) {
      if (record.expiresAt <= now) {
        downloadTickets.delete(ticket);
      }
    }
  },
  2 * 60 * 1000,
);

// ─────────────────────────  辅助函数  ───────────────────────────────────────

interface FlatFile {
  itemId: string;
  zipPath: string; // ZIP 包内的相对路径
}

/**
 * 递归展开单个 drive item。
 * - 如果是文件，直接写入 result。
 * - 如果是文件夹，读取其子项（含分页）并继续递归。
 */
async function expandItem(
  graphClient: ReturnType<typeof createGraphClient>,
  driveId: string,
  itemId: string,
  basePath: string,
  result: FlatFile[],
): Promise<void> {
  // 先查询项目元数据，判断是文件还是文件夹
  const item = await graphClient
    .api(`/drives/${driveId}/items/${itemId}`)
    .select("id,name,folder,file,size")
    .get();

  if (item.folder) {
    // 文件夹：继续展开其子项
    await expandFolder(
      graphClient,
      driveId,
      itemId,
      basePath ? `${basePath}/${item.name}` : item.name,
      result,
    );
  } else {
    // 文件：直接加入待打包列表
    result.push({
      itemId,
      zipPath: basePath ? `${basePath}/${item.name}` : item.name,
    });
  }
}

/**
 * 枚举文件夹下所有子项（处理 @odata.nextLink 分页）。
 */
async function expandFolder(
  graphClient: ReturnType<typeof createGraphClient>,
  driveId: string,
  folderId: string,
  folderPath: string,
  result: FlatFile[],
): Promise<void> {
  let endpoint: string | null = `/drives/${driveId}/items/${folderId}/children`;

  while (endpoint) {
    const page: { value?: any[]; "@odata.nextLink"?: string } =
      await graphClient.api(endpoint).select("id,name,folder,file,size").get(); // eslint-disable-line
    const children: any[] = page.value ?? [];

    for (const child of children) {
      if (child.folder) {
        await expandFolder(
          graphClient,
          driveId,
          child.id,
          `${folderPath}/${child.name}`,
          result,
        );
      } else {
        result.push({
          itemId: child.id,
          zipPath: `${folderPath}/${child.name}`,
        });
      }
    }

    // 如果存在下一页链接，继续拉取
    endpoint = page["@odata.nextLink"] ?? null;
  }
}

// ─────────────────────────  对外 API  ───────────────────────────────────────

/**
 * 启动新的归档下载任务。
 *
 * @param containerId SPE 容器（Drive）ID
 * @param itemIds 要归档的项目 ID 列表（文件或文件夹）
 * @param userToken 已验证通过的用户访问令牌（用于 OBO 换取 Graph Token）
 * @returns 任务 ID
 */
export async function startDownloadJob(
  containerId: string,
  itemIds: string[],
  userToken: string,
): Promise<string> {
  const jobId = uuidv4();

  const job: Job = {
    status: "queued",
    processedFiles: 0,
    totalFiles: 0,
    currentItem: "",
    errors: [],
    createdAt: Date.now(),
  };
  jobs.set(jobId, job);

  // 异步后台执行，保证 HTTP 请求可以立即返回 jobId
  processJob(jobId, containerId, itemIds, userToken).catch((err) => {
    const j = jobs.get(jobId);
    if (j) {
      j.status = "failed";
      j.errors.push(`Job failed: ${err.message}`);
    }
  });

  return jobId;
}

/**
 * 获取任务当前进度。
 * 如果 jobId 不存在或已过期，返回 null。
 */
export function getJobProgress(jobId: string): JobProgress | null {
  const job = jobs.get(jobId);
  if (!job) return null;
  const { zipBuffer: _ignored, createdAt: _c, ...progress } = job;
  return progress;
}

/**
 * 读取 ready 任务的 ZIP Buffer。
 * 任务不存在、未 ready 或已过期时返回 null。
 */
export function getJobBuffer(jobId: string): Buffer | null {
  const job = jobs.get(jobId);
  if (!job || job.status !== "ready" || !job.zipBuffer) return null;
  return job.zipBuffer;
}

/**
 * 创建短时有效、单次消费的下载票据（给浏览器原生下载器使用）。
 */
export function createDownloadTicket(jobId: string, filename: string): string {
  const ticket = uuidv4();
  downloadTickets.set(ticket, {
    jobId,
    filename,
    expiresAt: Date.now() + DOWNLOAD_TICKET_TTL_MS,
  });
  return ticket;
}

/**
 * 消费并作废票据。
 * 票据无效或过期时返回 null。
 */
export function consumeDownloadTicket(
  ticket: string,
): { jobId: string; filename: string } | null {
  const record = downloadTickets.get(ticket);
  if (!record) return null;

  // 先删除再校验有效期，确保票据永远只能被消费一次
  downloadTickets.delete(ticket);
  if (record.expiresAt <= Date.now()) {
    return null;
  }

  return { jobId: record.jobId, filename: record.filename };
}

// ─────────────────────────  后台处理流程  ───────────────────────────────────

async function processJob(
  jobId: string,
  containerId: string,
  itemIds: string[],
  userToken: string,
): Promise<void> {
  const job = jobs.get(jobId)!;

  // ── 1. 准备 Graph 客户端 ────────────────────────────────────────────────
  job.status = "preparing";
  job.currentItem = "Initialising…";

  let graphToken: string;
  try {
    graphToken = await getGraphToken(userToken);
  } catch (err: any) {
    job.status = "failed";
    job.errors.push(`Graph token error: ${err.message}`);
    return;
  }

  const graphClient = createGraphClient(graphToken);

  // ── 2. 将所选项展开为扁平文件列表 ───────────────────────────────────────
  job.currentItem = "Expanding folder structure…";
  const flatFiles: FlatFile[] = [];

  for (const itemId of itemIds) {
    try {
      await expandItem(graphClient, containerId, itemId, "", flatFiles);
    } catch (err: any) {
      job.errors.push(`Failed to expand item ${itemId}: ${err.message}`);
    }
  }

  // 容量防护：空任务/文件数超限直接失败
  if (flatFiles.length === 0) {
    job.status = "failed";
    job.errors.push("No files found to archive.");
    return;
  }
  if (flatFiles.length > MAX_FILES) {
    job.status = "failed";
    job.errors.push(
      `Too many files (${flatFiles.length}). Maximum is ${MAX_FILES}.`,
    );
    return;
  }

  job.totalFiles = flatFiles.length;

  // ── 3. 构建 ZIP ──────────────────────────────────────────────────────────
  job.status = "zipping";

  const chunks: Buffer[] = [];
  const passThrough = new PassThrough();
  passThrough.on("data", (chunk: Buffer) => chunks.push(chunk));

  const archive = archiver("zip", { zlib: { level: 6 } });
  archive.pipe(passThrough);

  let totalBytes = 0;

  for (let i = 0; i < flatFiles.length; i++) {
    const { itemId, zipPath } = flatFiles[i];
    job.currentItem = zipPath;
    job.processedFiles = i;

    try {
      // 通过 Graph /content 端点下载文件内容。
      // 在 SPE 容器场景下，@microsoft.graph.downloadUrl 可靠性较差；
      // 使用携带 Bearer Token 的 /content 能稳定覆盖不同 Drive 类型，
      // 并自动跟随重定向到真实存储地址。
      const contentUrl = `https://graph.microsoft.com/v1.0/drives/${containerId}/items/${itemId}/content`;
      const fileResponse = await fetch(contentUrl, {
        headers: { Authorization: `Bearer ${graphToken}` },
        redirect: "follow",
      });
      if (!fileResponse.ok) {
        job.errors.push(
          `Failed to download ${zipPath}: HTTP ${fileResponse.status}`,
        );
        continue;
      }

      const arrayBuffer = await fileResponse.arrayBuffer();
      const buffer = Buffer.from(arrayBuffer);

      // 按“真实已下载字节数”做总大小限制，避免打包过程失控
      totalBytes += buffer.length;
      if (totalBytes > MAX_BYTES) {
        job.status = "failed";
        job.errors.push(
          `Archive would exceed the ${MAX_BYTES / 1024 / 1024} MB size limit.`,
        );
        archive.abort();
        return;
      }

      archive.append(buffer, { name: zipPath });
      job.processedFiles = i + 1;
    } catch (err: any) {
      job.errors.push(`Error adding ${zipPath}: ${err.message}`);
    }
  }

  // 归档收尾：等待流真正结束后再拼接 Buffer，避免拿到不完整数据
  await new Promise<void>((resolve, reject) => {
    passThrough.on("finish", resolve);
    passThrough.on("error", reject);
    archive.on("error", reject);
    archive.finalize();
  });

  job.zipBuffer = Buffer.concat(chunks);
  job.status = "ready";
  job.currentItem = "";
}
